  ('C.11.4.1.1', 'Coğrafya', 11, 4, 'Küresel Ortam: Bölgeler ve Ülkeler', 'Gelişmiş ve gelişmekte olan ülkeler', 'Ülkelerin ekonomik gelişmişliğini ölçen göstergeleri ve gelişme farklarını açıklar.'),
  ('C.11.4.1.2', 'Coğrafya', 11, 4, 'Küresel Ortam: Bölgeler ve Ülkeler', 'Kıtaların coğrafi özellikleri: Asya', 'Asya kıtasının fiziki, beşeri ve ekonomik özelliklerini açıklar.'),
  ('C.11.4.2.1', 'Coğrafya', 11, 4, 'Küresel Ortam: Bölgeler ve Ülkeler', 'Kıtaların coğrafi özellikleri: Avrupa ve Afrika', 'Avrupa ve Afrika kıtalarının temel coğrafi özelliklerini ve sorunlarını açıklar.'),
  ('C.11.4.2.2', 'Coğrafya', 11, 4, 'Küresel Ortam: Bölgeler ve Ülkeler', 'Amerika ve Avustralya/Okyanusya', 'Kuzey ve Güney Amerika ile Avustralya-Okyanusya''nın temel coğrafi özelliklerini açıklar.'),
  ('C.11.5.1.1', 'Coğrafya', 11, 5, 'Ekonomik Coğrafya', 'Tarım sistemleri ve gıda güvenliği', 'Dünya''daki farklı tarım sistemlerini karşılaştırır; gıda güvenliği sorununu açıklar.'),
  ('C.11.5.1.2', 'Coğrafya', 11, 5, 'Ekonomik Coğrafya', 'Enerji kaynakları ve küresel enerji politikası', 'Fosil yakıtları ve yenilenebilir enerji kaynaklarını küresel politika çerçevesinde açıklar.'),
  ('C.11.5.2.1', 'Coğrafya', 11, 5, 'Ekonomik Coğrafya', 'Küresel ticaret ve ekonomik bloklar', 'Dünya ticaretinin örüntüsünü ve başlıca ekonomik blokları (AB, NAFTA, ASEAN) açıklar.'),
  ('C.11.6.1.1', 'Coğrafya', 11, 6, 'Siyasi Coğrafya', 'Devlet ve sınır kavramları', 'Devlet, ülke ve sınır kavramlarını açıklar; sınır anlaşmazlıklarının nedenlerini yorumlar.'),
  ('C.11.6.1.2', 'Coğrafya', 11, 6, 'Siyasi Coğrafya', 'Uluslararası örgütler ve küresel yönetişim', 'BM, AB, NATO gibi uluslararası örgütlerin yapısını ve işlevini açıklar.'),
  ('C.11.7.1.1', 'Coğrafya', 11, 7, 'Doğal Kaynaklar ve Çevre', 'Su kaynakları ve su güvenliği', 'Küresel su kıtlığı sorununu ve uluslararası su politikalarını açıklar.'),
  ('C.11.7.1.2', 'Coğrafya', 11, 7, 'Doğal Kaynaklar ve Çevre', 'Çevre sorunları ve uluslararası işbirliği', 'Küresel çevre sorunlarını ve bu sorunların çözümüne yönelik uluslararası anlaşmaları açıklar.'),
  ('C.12.1.1.1', 'Coğrafya', 12, 1, 'Türkiye''nin Jeopolitik Konumu', 'Türkiye''nin coğrafi konumu ve komşuları', 'Türkiye''nin matematiksel ve özel konumunun jeopolitik önemini açıklar.'),
  ('C.12.1.1.2', 'Coğrafya', 12, 1, 'Türkiye''nin Jeopolitik Konumu', 'Türkiye''nin Orta Doğu politikasında coğrafyanın rolü', 'Coğrafyanın Türkiye''nin bölgesel politikasını nasıl şekillendirdiğini açıklar.'),
  ('C.12.2.1.1', 'Coğrafya', 12, 2, 'Küresel Çevre Sorunları', 'Erozyon, çölleşme ve toprak bozulumu', 'Erozyon türlerini, çölleşme sürecini ve Türkiye''deki durumu açıklar.'),
  ('C.12.2.1.2', 'Coğrafya', 12, 2, 'Küresel Çevre Sorunları', 'Orman yangınları ve biyoçeşitlilik kaybı', 'Orman yangınlarının nedenlerini, etkilerini ve biyoçeşitlilik üzerindeki sonuçlarını açıklar.'),
  ('C.12.3.1.1', 'Coğrafya', 12, 3, 'Türkiye''de Doğal Afetler ve Risk Yönetimi', 'Deprem risk haritası ve hazırlık', 'Türkiye''nin deprem kuşaklarını haritalandırır; afet hazırlık stratejilerini değerlendirir.'),
  ('C.12.3.1.2', 'Coğrafya', 12, 3, 'Türkiye''de Doğal Afetler ve Risk Yönetimi', 'Sel, heyelan ve kuraklık yönetimi', 'Türkiye''de sıkça yaşanan doğal afetlerin coğrafi dağılışını ve önlem stratejilerini açıklar.'),
  ('C.12.4.1.1', 'Coğrafya', 12, 4, 'Sürdürülebilir Kalkınma', 'Yenilenebilir enerji kaynakları ve Türkiye', 'Türkiye''nin güneş, rüzgar, hidroelektrik ve jeotermal enerji potansiyelini açıklar.'),
  ('C.12.4.1.2', 'Coğrafya', 12, 4, 'Sürdürülebilir Kalkınma', 'Akıllı kentler ve sürdürülebilir kentleşme', 'Akıllı kent kavramını ve sürdürülebilir kentleşme uygulamalarını açıklar.'),
  ('C.12.5.1.1', 'Coğrafya', 12, 5, 'Coğrafya Araştırma Yöntemleri', 'Uzaktan algılama ve GIS', 'Uzaktan algılama ve CBS''nin coğrafi araştırmalardaki kullanımını açıklar.'),
  ('C.12.5.1.2', 'Coğrafya', 12, 5, 'Coğrafya Araştırma Yöntemleri', 'Alan çalışması ve veri toplama', 'Coğrafi alan çalışması yöntemlerini ve veri toplama tekniklerini açıklar.'),
  ('C.12.6.1.1', 'Coğrafya', 12, 6, 'Türkiye Ekonomisinin Güncel Sorunları', 'Bölgesel kalkınma eşitsizlikleri', 'Türkiye''nin bölgesel gelişmişlik farklarını ve kalkınma ajanslarının rolünü açıklar.'),
  ('C.12.6.1.2', 'Coğrafya', 12, 6, 'Türkiye Ekonomisinin Güncel Sorunları', 'Turizmin coğrafi boyutu ve önemi', 'Türkiye''nin turizm bölgelerini ve turizmin ekonomiye katkısını değerlendirir.'),
  ('C.9.1.1.1', 'Coğrafya', 9, 1, 'Coğrafyanın Konusu, Önemi ve Çalışma Yöntemleri', 'Coğrafya biliminin tanımı ve önemi', 'Coğrafyanın tanımını yapar; insan-doğa ilişkisini inceleyen bilim dalı olarak açıklar.'),
  ('C.9.1.1.2', 'Coğrafya', 9, 1, 'Coğrafyanın Konusu, Önemi ve Çalışma Yöntemleri', 'Harita bilgisi ve koordinat sistemi', 'Harita türlerini, projeksiyon sistemlerini ve koordinat sistemini açıklar.'),
  ('C.9.2.1.1', 'Coğrafya', 9, 2, 'Doğa ve İnsan', 'Dünyanın şekli ve hareketleri', 'Dünyanın şeklini ve boyutlarını açıklar; günlük ve yıllık hareketlerin sonuçlarını yorumlar.'),
  ('C.9.2.1.2', 'Coğrafya', 9, 2, 'Doğa ve İnsan', 'Zaman ve takvim', 'Yerel zaman, dilim zamanı ve takvim kavramlarını açıklar; hesaplamalar yapar.'),
  ('C.9.3.1.1', 'Coğrafya', 9, 3, 'Litosfer', 'Yer''in iç yapısı ve levha tektoniği', 'Yer''in katmanlarını açıklar; levha tektoniği kuramını ve jeolojik olaylarla ilişkisini yorumlar.'),
  ('C.9.3.1.2', 'Coğrafya', 9, 3, 'Litosfer', 'Deprem ve volkanizma', 'Deprem ve volkanik olayların oluşumunu açıklar; dünya üzerindeki dağılımını yorumlar.'),
  ('C.9.3.2.1', 'Coğrafya', 9, 3, 'Litosfer', 'Yer şekillerinin oluşumu', 'İç ve dış kuvvetlerin yer şekillerini nasıl oluşturduğunu açıklar.'),
  ('C.9.4.1.1', 'Coğrafya', 9, 4, 'Atmosfer', 'Atmosferin yapısı ve bileşimi', 'Atmosferin katmanlarını, bileşimini ve önemini açıklar.'),
  ('C.9.4.1.2', 'Coğrafya', 9, 4, 'Atmosfer', 'İklim elemanları: sıcaklık ve yağış', 'Sıcaklık ve yağışı etkileyen faktörleri açıklar; küresel dağılımı yorumlar.'),
  ('C.9.4.2.1', 'Coğrafya', 9, 4, 'Atmosfer', 'İklim tipleri', 'Dünya''daki başlıca iklim tiplerini özellikleri ve dağılışı açısından açıklar.'),
  ('C.9.5.1.1', 'Coğrafya', 9, 5, 'Hidrosfer', 'Su döngüsü ve yeraltı suları', 'Su döngüsünü ve yeraltı sularının oluşumunu açıklar.'),
  ('C.9.5.1.2', 'Coğrafya', 9, 5, 'Hidrosfer', 'Akarsular, göller ve denizler', 'Akarsu rejimleri, göl türleri ve denizlerin özelliklerini açıklar.'),
  ('C.9.6.1.1', 'Coğrafya', 9, 6, 'Biyosfer', 'Toprak oluşumu ve bozunumu', 'Toprak oluşum sürecini ve toprak bozunumunun nedenlerini açıklar.'),
  ('C.9.6.1.2', 'Coğrafya', 9, 6, 'Biyosfer', 'Doğal bitki örtüsü', 'Dünya''nın başlıca doğal bitki örtüsü tiplerini iklimle ilişkilendirerek açıklar.'),
  ('C.9.7.1.1', 'Coğrafya', 9, 7, 'Nüfus', 'Nüfusun dağılışı ve nüfus yoğunluğu', 'Dünya nüfusunun dağılışını etkileyen faktörleri açıklar; nüfus yoğunluğunu hesaplar.'),
  ('C.9.7.1.2', 'Coğrafya', 9, 7, 'Nüfus', 'Nüfus artışı ve demografik geçiş', 'Nüfus artışını etkileyen faktörleri ve demografik geçiş modelini açıklar.'),
  ('C.9.8.1.1', 'Coğrafya', 9, 8, 'Göç ve Yerleşme', 'Göç türleri ve nedenleri', 'İç ve dış göçleri, itici ve çekici faktörleri açıklar; Türkiye''den örnekler verir.'),
  ('C.9.8.1.2', 'Coğrafya', 9, 8, 'Göç ve Yerleşme', 'Kırsal ve kentsel yerleşme', 'Yerleşme türlerini ve kentleşme sürecini açıklar; plansız kentleşmenin sonuçlarını yorumlar.'),
  ('FB.3.1.1', 'Fen Bilimleri', 3, 1, 'BİLİMSEL KEŞİF YOLCULUĞU', 'Bilimsel bilgiye ulaşma yollarını sorgulayabilme', 'Merak ettiği bilimsel bir konuyu tanımlar. İlgili konu hakkında sorular sorar. Sorularını cevaplamaya yönelik bilgi toplar. Bilimsel bilgiye ulaşma yollarının uygunluğunu değerlendirir. Toplanan bilgiler üzerinden bilimsel bilgiye ulaşma yollarına ilişkin çıkarım yapar.'),
  ('FB.3.1.2', 'Fen Bilimleri', 3, 1, 'BİLİMSEL KEŞİF YOLCULUĞU', 'Bilim insanlarının özelliklerine ilişkin genelleme yapabilme', 'Bilim insanları hakkında bilgi toplar. Bilim insanlarının ortak özelliklerini belirler. Bilim insanlarının ortak olmayan özelliklerini belirler. Örüntüler üzerinden bilim insanlarının özellikleri hakkında önermede bulunur.'),
  ('FB.3.2.1', 'Fen Bilimleri', 3, 2, 'CANLILAR DÜNYASINA YOLCULUK', 'Canlıları; mikroskopla görülebilen canlılar, mantarlar, bitkiler ve hayvanlar olarak sınıflandırabilme', 'Canlıların benzer ve farklı niteliklerini belirler. Canlıları niteliklerine göre ayırır. Canlıları gruplandırır. Canlıları etiketler.'),
  ('FB.3.2.2', 'Fen Bilimleri', 3, 2, 'CANLILAR DÜNYASINA YOLCULUK', 'Canlıların çevrelerini farklı yollarla algılamaları konusunda bilimsel çıkarım yapabilme', 'Canlıların çevrelerini algılama biçimlerine ilişkin nitelikleri tanımlar. Duyu organlarının işlevleri ile ilgili veri toplayarak kaydeder. Canlıların çevrelerini farklı biçimlerde algılamalarına ilişkin verileri yorumlayarak değerlendirir.'),
  ('FB.3.2.3', 'Fen Bilimleri', 3, 2, 'CANLILAR DÜNYASINA YOLCULUK', 'Canlıların yaşam döngülerini açıklamada tümevarımsal akıl yürütebilme', 'Canlıların yaşam döngüleri ile ilgili örüntüleri bulur. Canlıların yaşam döngüleri ile ilgili genelleme yapar.'),
  ('FB.3.3.1', 'Fen Bilimleri', 3, 3, 'YER BİLİMCİLER İŞ BAŞINDA', 'Kayaçlar, madenler ve mineraller ile ilgili tümdengelimsel akıl yürütebilme', 'Kayaçlar, madenler ve mineralleri belirler. Kayaçlar, madenler ve mineraller arasında ilişki kurar. Kayaçlar, madenler ve mineraller arasında genelden genele veya genelden özele çıkarım yapar.'),
  ('FB.3.3.2', 'Fen Bilimleri', 3, 3, 'YER BİLİMCİLER İŞ BAŞINDA', 'Fosil oluşumu ile ilgili sentez yapabilme', 'Fosil oluşumunu gösteren sürecin bütün ve parçalarını belirler. Süreci oluşturan aşamalar arasında ilişki kurar. Fosillerin oluşum sürecini oluşturan aşamaları uygun sırayla bir bütün hâline getirir.'),
  ('FB.3.4.1', 'Fen Bilimleri', 3, 4, 'MADDEYİ TANIYALIM, KARIŞTIRIP AYIRALIM', 'Çevresindeki maddeleri hâllerine göre sınıflandırabilme', 'Çevresindeki maddelerin niteliklerini tanımlar. Çevresindeki maddeleri niteliklerine göre ayırır. Çevresindeki maddeleri hâllerine göre gruplandırır. Maddeleri hâllerine göre katı, sıvı ve gaz olarak etiketler.'),
  ('FB.3.4.2', 'Fen Bilimleri', 3, 4, 'MADDEYİ TANIYALIM, KARIŞTIRIP AYIRALIM', 'Günlük yaşamda karşılaştığı karışımların ayrılmasında kullanılabilecek uygun yöntemleri kullanarak deney yapabilme', 'Karışımların ayrılmasında kullanılabilecek yöntemlerle ilgili deney tasarlar. Karışımların ayrılmasına ilişkin deney sonucu ile hipotezi arasında uyumsuzluk olduğunda deneyini tekrar eder ve/veya hipotezini yeniler.'),
  ('FB.3.4.3', 'Fen Bilimleri', 3, 4, 'MADDEYİ TANIYALIM, KARIŞTIRIP AYIRALIM', 'Atıkların ayrıştırılmasına ilişkin problem çözebilme', 'Atıkların ayrıştırılmasına ilişkin problemi yapılandırır. Atıkların ayrıştırılmasına ilişkin problemi özetler. Atıkların ayrıştırılmasına ilişkin çözüm önerilerini gözleme ya da veriye dayalı tahmin eder. Atıkların ayrıştırılmasına ilişkin problemin çözümüne yönelik önermeler üzerinden akıl yürütür. Atıkların ayrıştırılmasına ilişkin problemin çözümüne yönelik yansıtmada/değerlendirmede bulunur.'),
  ('FB.3.5.1', 'Fen Bilimleri', 3, 5, 'HAREKETİ KEŞFEDİYORUM', 'Varlıkların hareket durumlarını gözleme dayalı tahmin edebilme', 'Varlıkların hareket durumlarına ilişkin ön gözlem ve/veya deneyimlerini ilişkilendirir. Varlıkların hareket durumlarına ilişkin çıkarım yapar. Varlıkların hareket durumlarının sonuçlarına ilişkin yargıda bulunur.'),
  ('FB.3.5.2', 'Fen Bilimleri', 3, 5, 'HAREKETİ KEŞFEDİYORUM', 'Kuvvetin varlıklar üzerindeki etkilerini bilimsel gözleme dayalı tahmin edebilme', 'Varlıkların hareketinin ve şekil değiştirmesinin nedenine ilişkin ön bilgi ve deneyimleriyle önerme oluşturur. Varlıkların hareketinin ve şekil değiştirmesinin nedenine ilişkin gözleme dayalı olan önermeleri karşılaştırır. Kuvvetin varlıkların hareketine ve şekil değiştirmesine etkilerine ilişkin tahminlerini temellendirmek için gözlem verilerinden sonuç çıkarır. Kuvvetin varlıkların hareketine ve şekil değiştirmesine etkileri ile ilgili gözlemlenmemiş duruma ilişkin tahminde bulunur. Kuvvetin varlıkların hareketine ve şekil değiştirmesine etkileri ile ilgili tahminlerinin geçerliliğini sorgular.'),
  ('FB.3.6.1', 'Fen Bilimleri', 3, 6, 'YAŞAMIMIZI KOLAYLAŞTIRAN ELEKTRİK', 'Bazı araç gereçlerin elektrikli olduğuna ilişkin bilimsel çıkarım yapabilme', 'Farklı araç gereçlerin niteliklerini tanımlar. Elektrikli araç gereçlerle ilgili veri toplayarak kaydeder. Elektrikli araç gereçlerle ilgili verileri değerlendirir.'),
  ('FB.3.6.2', 'Fen Bilimleri', 3, 6, 'YAŞAMIMIZI KOLAYLAŞTIRAN ELEKTRİK', 'Elektrikli araç gereçlerin güvenli kullanımı ile ilgili eleştirel düşünebilme', 'Elektrikli araç gereçlerin güvenli kullanımı ile ilgili verilen bir olay/konu/problem veya durumu sorgular. Elektrikli araç gereçlerin kullanımında güvenliğin sağlanabileceğine yönelik akıl yürütür. Akıl yürütmeyle ulaştığı çıkarımları yansıtır.'),
  ('FB.3.6.3', 'Fen Bilimleri', 3, 6, 'YAŞAMIMIZI KOLAYLAŞTIRAN ELEKTRİK', 'Elektriği tasarruflu kullanma konusunda bilimsel veriye dayalı tahmin edebilme', 'Elektriği tasarruflu kullanma konusunda verilere ve/veya ön bilgilere dayalı önerme oluşturur. Elektriği tasarruflu kullanma üzerine nicel ölçüm verilerine dayalı önermelerini gerekçelendirir. Hesaplamalarına dayalı olarak tahmin eder. Tahminlerin geçerliliğini sorgular.'),
  ('FB.3.7.1', 'Fen Bilimleri', 3, 7, 'TOPRAĞI TANIYORUM, TARIMI KEŞFEDİYORUM', 'Toprak oluşumuna ve yapısına ilişkin bilimsel gözlem yapabilme', 'Toprağın oluşumuna ve yapısına ilişkin nitelikleri tanımlar. Toprağın yapısına ilişkin veri toplayarak kaydeder. Toprağın yapısına ilişkin topladığı verileri açıklar.'),
  ('FB.3.7.2', 'Fen Bilimleri', 3, 7, 'TOPRAĞI TANIYORUM, TARIMI KEŞFEDİYORUM', 'Bir bitkinin yetişmesi için gerekenlere ilişkin genelleme yapabilme', 'Çevresinde bulunan tarım ürünlerinin nasıl yetiştirildiği konusunda araştırma yaparak bilgi toplar. Bitki yetiştirmek için gerekli ortak özellikleri belirler. Farklı bitkilerin yetiştirilmesinde ortak olmayan özellikleri belirler. Bir bitki yetiştirmek için yapılması gerekenler konusunda önermede bulunur.'),
  ('FB.3.8.1', 'Fen Bilimleri', 3, 8, 'CANLILARIN YAŞAM ALANLARINA YOLCULUK', 'Canlıların yaşam alanlarının özelliklerini belirlemeye yönelik kanıt kullanabilme', 'Canlıların yaşam alanlarının özelliklerine ilişkin veri toplayarak kaydeder. Canlıların yaşam alanlarına ilişkin veri setleri oluşturur. Canlıların yaşam alanlarının özelliklerine ilişkin veriye dayalı açıklama yapar.'),
  ('FB.3.8.2', 'Fen Bilimleri', 3, 8, 'CANLILARIN YAŞAM ALANLARINA YOLCULUK', 'Yaşam alanındaki canlı çeşitliliğini operasyonel olarak tanımlayabilme', 'Yaşam alanının özelliklerini tanımlar. Yaşam alanındaki canlı çeşitliliği ile ilgili ölçüm yapar. Canlı çeşitliliğinin tanımını yapar.'),
  ('FB.3.8.3', 'Fen Bilimleri', 3, 8, 'CANLILARIN YAŞAM ALANLARINA YOLCULUK', 'Yaşam alanlarının korunması için yapılacakları sorgulayabilme', 'Merak ettiği konuyu tanımlar. İlgili konu hakkında sorular sorar. İlgili konu hakkında bilgi toplar. Toplanan bilgilerin doğruluğunu değerlendirir. Toplanan bilgiler üzerinde çıkarım yapar.'),
  ('FB.4.1.1', 'Fen Bilimleri', 4, 1, 'BİLİME YOLCULUK', 'Bilimin özellikleri ile ilgili yansıtma yapabilme', 'Bilim ile ilgili bilgi ve deneyimini gözden geçirir. Bilimin özellikleri ile ilgili çıkarım yapar. Bilimin özellikleri ile ilgili ulaşılan çıkarımları değerlendirir.'),
  ('FB.4.1.2', 'Fen Bilimleri', 4, 1, 'BİLİME YOLCULUK', 'Bilgi kaynağının güvenilirliğini sorgulayabilme', 'Merak ettiği bilimsel bir konuyu tanımlar. İlgili konu hakkında sorular sorar. İlgili konu hakkında teknolojik araçlar ve diğer kaynakları kullanarak bilgi toplar. Toplanan bilgilerden hareketle bilginin doğruluğunu değerlendirir. Yaptığı değerlendirmeler sonucunda bilgi kaynaklarının güvenilirliği ile ilgili çıkarım yapar.'),
  ('FB.4.2.1', 'Fen Bilimleri', 4, 2, 'SAĞLIKLI BESLENİYORUM', 'Besin içeriklerini ayırt etmek için deney yapabilme', 'Besinlerdeki protein, karbohidrat, yağ ve su içeriğini ayırt etmek için deney tasarlar. Yaptığı deneyde veri analizi yapar.'),
  ('FB.4.2.2', 'Fen Bilimleri', 4, 2, 'SAĞLIKLI BESLENİYORUM', 'Besinlerde vitamin ve/veya mineral bulunduğuna ilişkin genelleme yapabilme', 'Besinlerdeki vitamin ve mineraller ile ilgili bilgi toplar. Besinlerdeki ortak olan özellikleri belirler. Besinlerdeki ortak olmayan özellikleri belirler. Örüntüler üzerinden besinlerde vitamin ve/veya minerallerin bulunduğu önermesinde bulunur.'),
  ('FB.4.2.3', 'Fen Bilimleri', 4, 2, 'SAĞLIKLI BESLENİYORUM', 'Besinlerin işlevleri ile ilgili hipotez oluşturabilme', 'Besinlerin işlevleri ile ilgili problemi tanımlar. Besinlerin işlevleri ve vücudumuzdaki görevleri arasındaki neden-sonuç ilişkilerini belirler. Besinlerin içerikleri ile ilgili verilen değişkenleri belirler. Besinlerin işlevleri ile ilgili değişkenleri kontrol eder. Besinlerin işlevleri ve sağlıklı yaşam arasındaki ilişkiye yönelik önerme sunar.'),
  ('FB.4.3.1', 'Fen Bilimleri', 4, 3, 'DÜNYA''MIZI KEŞFEDELİM', 'Dünya''nın şekli ile ilgili bilimsel gözleme dayalı tahmin yapabilme', 'Dünya''nın şekli ile ilgili ön bilgi ve deneyimlerine dayalı önerme oluşturur. Dünya''nın şekli ile ilgili gözleme dayalı olan önermeleri karşılaştırır. Dünya''nın şekli ile ilgili tahminlerini temellendirmek için gözlem verilerinden sonuç çıkarır. Dünya''nın şekli ile ilgili veriye dayalı tahminde bulunur. Dünya''nın şekli ile ilgili verilere dayalı tahminlerin geçerliğini sorgular.'),
  ('FB.4.3.2', 'Fen Bilimleri', 4, 3, 'DÜNYA''MIZI KEŞFEDELİM', 'Dünya''nın yapısıyla ilgili bilimsel model oluşturabilme', 'Dünya''nın yapısını açıklamak için model önerir. Dünya''nın yapısını açıklamak için yeni kanıtlarla modeli geliştirir.'),
  ('FB.4.3.3', 'Fen Bilimleri', 4, 3, 'DÜNYA''MIZI KEŞFEDELİM', 'Dünya''nın hareketlerini gözlemlerine dayanarak tahmin edebilme', 'Dünya''nın hareketleri ile ilgili önceki gözlem ve/veya deneyimini ilişkilendirir. Dünya''nın hareketlerine ilişkin çıkarım yapar. Dünya''nın hareketlerinin sonuçlarına ilişkin yargıda bulunur.'),
  ('FB.4.4.1', 'Fen Bilimleri', 4, 4, 'MADDENİN DEĞİŞİMİ', 'Maddelerin hâl değişimine yönelik bilimsel çıkarım yapabilme', 'Maddelerin hâllerine yönelik nitelikleri tanımlar. Maddelerin hâl değişimine yönelik verileri kaydeder. Maddelerin hâl değişimine yönelik verileri yorumlayarak değerlendirir.'),
  ('FB.4.4.2', 'Fen Bilimleri', 4, 4, 'MADDENİN DEĞİŞİMİ', 'Maddelerin ısı etkisiyle değişimine yönelik deney yapabilme', 'Maddelerin ısı etkisiyle değişimine yönelik deney tasarlar. Maddelerin ısı etkisiyle değişimine yönelik veri analizi yapar.'),
  ('FB.4.5.1', 'Fen Bilimleri', 4, 5, 'MIKNATISI KEŞFEDİYORUM', 'Mıknatısın kutupları ve birbirleriyle etkileşimleri ile ilgili tümevarımsal akıl yürütebilme', 'Mıknatıs çeşitlerinin kutupları ve birbiriyle etkileşimleri ile ilgili örüntü bulur. Mıknatısın kutupları ve birbiriyle etkileşimleri ile ilgili genelleme yapar.'),
  ('FB.4.5.2', 'Fen Bilimleri', 4, 5, 'MIKNATISI KEŞFEDİYORUM', 'Mıknatısın etki ettiği maddelere ilişkin bilimsel gözleme dayalı tahmin yapabilme', 'Mıknatısın etki ettiği maddelere ilişkin ön bilgi ve deneyimlerine dayanarak önerme oluşturur. Mıknatısın etki ettiği maddelere ilişkin gözleme dayalı önermeleri karşılaştırır. Mıknatısın etki ettiği maddelere ilişkin tahminlerini temellendirmek için gözlem verilerinden sonuç çıkarır. Mıknatısın etki ettiği maddelerle ilgili gözlemlenmemiş duruma ilişkin tahminde bulunur. Tahminlerin geçerliğini sorgular.'),
  ('FB.4.5.3', 'Fen Bilimleri', 4, 5, 'MIKNATISI KEŞFEDİYORUM', 'Mıknatısın kullanım alanlarına yönelik bilimsel sorgulama yapabilme', 'Mıknatısın kullanım alanlarına yönelik bir soru veya problem tanımlar. Sorusunu/problemini cevaplamada kullanabileceği bir model geliştirir. Modelini oluşturmaya yönelik araştırma planlayarak gerçekleştirir. Oluşturduğu modele ilişkin verileri analiz ederek yorumlar. Oluşturduğu modelle ilgili sorunlara ilişkin kanıta dayalı açıklama yaparak çözüm üretir. Oluşturduğu modeli değerlendirerek paylaşır.'),
  ('FB.4.6.1', 'Fen Bilimleri', 4, 6, 'ENERJİ DEDEKTİFLERİ', 'Basit bir elektrik devresi kurmaya ilişkin bilimsel sorgulama yapabilme', 'Devre elemanlarını kullanarak basit bir elektrik devresi kurmaya ilişkin soru veya problemi tanımlar. Sorusunu/problemini cevaplamada kullanacağı basit bir elektrik devresi modeli geliştirir. Basit bir elektrik devresinde devre elemanlarına ve işlevlerine ilişkin araştırmayı planlayarak gerçekleştirir. Basit bir elektrik devresine ilişkin verileri analiz ederek yorumlar. Elektrik devresinin çalışıp çalışmamasına yönelik kanıta dayalı açıklama yaparak çözüm üretir. Çalışan basit bir elektrik devresi kurmaya ilişkin bilgiyi değerlendirerek paylaşır.'),
  ('FB.4.6.2', 'Fen Bilimleri', 4, 6, 'ENERJİ DEDEKTİFLERİ', 'Elektrik üretiminde yenilenebilir ve yenilenemeyen enerji kaynaklarını kullanmaya ilişkin eleştirel düşünebilme', 'Elektrik üretiminde yenilenebilir ve yenilenemeyen enerji kaynaklarını kullanmaya ilişkin bir durumu veya problemi sorgular. Elektrik üretiminde yenilenebilir ve yenilenemeyen enerji kaynaklarını kullanmaya ilişkin durum veya problemin canlılar ve çevre üzerine etkileri konusunda akıl yürütür. Enerji kaynaklarının sürdürülebilirliklerine ilişkin akıl yürütmeyle ulaştığı çıkarımları yansıtır.'),
  ('FB.4.7.1', 'Fen Bilimleri', 4, 7, 'IŞIĞIN PEŞİNDE', 'Görme olayının gerçekleşebilmesi için ışığın rolüne ilişkin deney yapabilme', 'Görme olayının gerçekleşebilmesi için ışığın rolüne ilişkin deney tasarlar. Görme olayında ışığın rolüne ilişkin deneyde veri analizi yapar.'),
  ('FB.4.7.2', 'Fen Bilimleri', 4, 7, 'IŞIĞIN PEŞİNDE', 'Doğal ve yapay ışık kaynaklarını karşılaştırabilme', 'Çevresindeki ışık kaynaklarına ilişkin özellikleri belirler. Işık kaynaklarının benzerliklerini listeler. Işık kaynaklarının farklılıklarını listeler.'),
  ('FB.4.7.3', 'Fen Bilimleri', 4, 7, 'IŞIĞIN PEŞİNDE', 'Işık kirliliğinin canlılara etkisine ilişkin probleme yönelik çözüm önerilerini değerlendirebilme', 'Işık kirliliğinin canlılara etkisine ilişkin problemi yapılandırır. Problemi özetler. Problemin çözümüne yönelik gözleme dayalı/mevcut bilgiye/veriye dayalı tahmin eder. Problemin çözümüne yönelik önermeler üzerinden akıl yürütür. Problemin çözümüne ilişkin yansıtmada/değerlendirmede bulunur.'),
  ('FB.4.8.1', 'Fen Bilimleri', 4, 8, 'SÜRDÜRÜLEBİLİR ŞEHİRLER VE TOPLULUKLAR', 'Sürdürülebilir bir yaşam alanı kurmaya ilişkin bilimsel sorgulama yapabilme', 'Sürdürülebilir bir yaşam alanı kurmaya ilişkin soru veya problem tanımlar. Sorusunu/problemini cevaplamada kullanabileceği bir sürdürülebilir yaşam alanı modeli geliştirir. Sürdürülebilir bir yaşam alanı kurmaya ilişkin araştırma planlayarak modelini gerçekleştirir. Yaşam alanının sürdürülebilirliğine ilişkin verileri analiz ederek yorumlar. Yaşam alanının sürdürülebilir olup olmadığına ilişkin kanıta dayalı açıklama yaparak çözüm üretir. Sürdürülebilir bir yaşam alanı kurmaya ilişkin bilgiyi değerlendirerek paylaşır.'),
  ('FB.5.1.1.1', 'Fen Bilimleri', 5, 1, 'Gökyüzündeki Komşularımız ve Biz', 'Güneş''in yapısı ve dönme hareketi ile ilgili bilgileri toplayabilme', 'Güneş''in yapısı ve dönme hareketi hakkında bilgiye ulaşmak için araçları belirler, bilgileri bulur ve kaydeder.'),
  ('FB.5.1.2.1', 'Fen Bilimleri', 5, 1, 'Gökyüzündeki Komşularımız ve Biz', 'Ay''ın özellikleri, dönme ve dolanma hareketleri ile ilgili bilimsel çıkarım yapabilme', 'Ay''ın niteliklerini tanımlar, verilerini kaydeder ve değerlendirir.'),
  ('FB.5.1.2.2', 'Fen Bilimleri', 5, 1, 'Gökyüzündeki Komşularımız ve Biz', 'Ay''ın evrelerini temsil eden bilimsel model oluşturabilme', 'Ay''ın evrelerini temsil eden model önerir ve yeni kanıtlara göre geliştirir.'),
  ('FB.5.1.3.1', 'Fen Bilimleri', 5, 1, 'Gökyüzündeki Komşularımız ve Biz', 'Güneş, Dünya ve Ay''ın birbirlerine göre hareketlerini ve hacimsel büyüklüklerini temsil eden model oluşturabilme', 'Güneş, Dünya ve Ay''ın hareketlerini ve büyüklüklerini temsil eden model önerir ve geliştirir.'),
  ('FB.5.2.1.1', 'Fen Bilimleri', 5, 2, 'Kuvveti Tanıyalım', 'Kuvveti büyüklüğü ile tanımlayabilme', 'Kuvvetin niteliklerini tanımlar, dinamometre ile ölçer ve Newton birimiyle ifade eder.'),
  ('FB.5.2.1.2', 'Fen Bilimleri', 5, 2, 'Kuvveti Tanıyalım', 'Dinamometre modeli tasarlayabilme', 'Basit araçlarla dinamometre modeli önerir ve geliştirir.'),
  ('FB.5.2.2.1', 'Fen Bilimleri', 5, 2, 'Kuvveti Tanıyalım', 'Kütleye etki eden yer çekimi kuvvetini ağırlık olarak tanımlayabilme', 'Kütle ve ağırlık kavramlarını tanımlar, dinamometre ile ağırlık ölçer.'),
  ('FB.5.2.3.1', 'Fen Bilimleri', 5, 2, 'Kuvveti Tanıyalım', 'Sürtünme kuvvetinin çeşitli ortamlardaki etkilerine yönelik tümevarımsal akıl yürütebilme', 'Sürtünme kuvveti ile ilgili örüntü oluşturur ve genelleme yapar.'),
  ('FB.5.2.3.2', 'Fen Bilimleri', 5, 2, 'Kuvveti Tanıyalım', 'Sürtünmeyi artırma veya azaltmaya yönelik bilimsel model tasarlayabilme', 'Sürtünmeyi artıran ve azaltan durumlar için model önerir ve geliştirir.'),
  ('FB.5.3.1.1', 'Fen Bilimleri', 5, 3, 'Canlıların Yapısına Yolculuk', 'Bitki ve hayvan hücrelerini karşılaştırabilme', 'Bitki ve hayvan hücrelerinin benzer ve farklı özelliklerini listeler.'),
  ('FB.5.3.1.2', 'Fen Bilimleri', 5, 3, 'Canlıların Yapısına Yolculuk', 'Hücre-doku-organ-sistem-organizma kavramlarını yapılandırabilme', 'Hiyerarşik ilişkileri ortaya koyar ve uyumlu bir bütün oluşturur.'),
  ('FB.5.3.2.1', 'Fen Bilimleri', 5, 3, 'Canlıların Yapısına Yolculuk', 'Destek ve hareket sistemine ait yapıları sınıflandırabilme', 'Destek ve hareket sistemine ait yapıları gruplandırır ve etiketler.'),
  ('FB.5.3.2.2', 'Fen Bilimleri', 5, 3, 'Canlıların Yapısına Yolculuk', 'Destek ve hareket sisteminin sağlığı için bilgi toplayabilme', 'Destek ve hareket sisteminin sağlığını korumaya yönelik bilgi toplar ve kaydeder.'),
  ('FB.5.4.1.1', 'Fen Bilimleri', 5, 4, 'Işığın Dünyası', 'Işığın her yönde doğrusal yol izlediğini gözlem yoluyla açıklayabilme', 'Işığın izlediği yolu gözlemleyerek niteliklerini tanımlar ve verilerini kaydeder.'),
  ('FB.5.4.2.1', 'Fen Bilimleri', 5, 4, 'Işığın Dünyası', 'Maddeleri ışığı geçirme durumlarına göre sınıflandırabilme', 'Maddeleri ışığı geçirme özelliğine göre ayrıştırır, gruplandırır ve etiketler.'),
  ('FB.5.4.3.1', 'Fen Bilimleri', 5, 4, 'Işığın Dünyası', 'Tam gölgeye yönelik bilimsel gözlem yapabilme', 'Tam gölgenin niteliklerini tanımlar, verilerini kaydeder ve değişkenlerini açıklar.'),
  ('FB.5.5.1.1', 'Fen Bilimleri', 5, 5, 'Maddenin Doğası', 'Maddeleri tanecikli, boşluklu ve hareketli yapısına göre sınıflandırabilme', 'Maddeleri katı, sıvı ve gaz olarak gruplandırır ve tanecik yapısına göre etiketler.'),
  ('FB.5.5.2.1', 'Fen Bilimleri', 5, 5, 'Maddenin Doğası', 'Isı ve sıcaklık kavramlarını karşılaştırabilme', 'Isı ve sıcaklığın özelliklerini, benzerlik ve farklılıklarını listeler.'),
  ('FB.5.5.2.2', 'Fen Bilimleri', 5, 5, 'Maddenin Doğası', 'Sıcaklığı farklı sıvıların karıştırılması sonucu ısı alışverişi olduğuna yönelik bilimsel çıkarım yapabilme', 'Farklı sıcaklıklardaki sıvılar arasındaki ısı alışverişini gözlemler ve değerlendirir.'),
  ('FB.5.5.3.1', 'Fen Bilimleri', 5, 5, 'Maddenin Doğası', 'Maddenin ısı etkisiyle hâl değiştirebileceğini bilimsel gözleme dayalı tahmin edebilme', 'Maddenin hâl değişimine ilişkin gözlem verilerinden tahmin yapar ve sorgular.'),
  ('FB.5.5.4.1', 'Fen Bilimleri', 5, 5, 'Maddenin Doğası', 'Maddeleri ısı iletimi bakımından sınıflandırabilme', 'Maddeleri ısı iletkeni veya yalıtkanı olarak gruplandırır ve etiketler.'),
  ('FB.5.5.4.2', 'Fen Bilimleri', 5, 5, 'Maddenin Doğası', 'Isı yalıtımını gösteren model oluşturabilme', 'Isı yalıtımı ile ilgili model önerir ve yeni kanıtlarla geliştirir.'),
  ('FB.5.6.1.1', 'Fen Bilimleri', 5, 6, 'Yaşamımızdaki Elektrik', 'Elektrik devresi elemanlarını sembollerine göre sınıflandırabilme', 'Devre elemanlarını sembollerinin olup olmamasına göre ayrıştırır, gruplandırır ve etiketler.'),
  ('FB.5.6.1.2', 'Fen Bilimleri', 5, 6, 'Yaşamımızdaki Elektrik', 'Şemasını çizdiği elektrik devresine uygun deney yapabilme', 'Elektrik devresi şeması çizer ve uygun deney düzeneği kurar.'),
  ('FB.5.6.2.1', 'Fen Bilimleri', 5, 6, 'Yaşamımızdaki Elektrik', 'Ampul parlaklığını etkileyen değişkenlere ilişkin hipotez oluşturabilme', 'Pil ve ampul sayısının parlaklığa etkisini araştırır, değişkenleri belirler ve hipotez kurar.'),
  ('FB.5.7.1.1', 'Fen Bilimleri', 5, 7, 'Sürdürülebilir Yaşam ve Geri Dönüşüm', 'Evsel atıklarda geri dönüştürülebilen ve dönüştürülemeyen maddeleri sınıflandırabilme', 'Evsel atıkları geri dönüştürülebilen ve dönüştürülemeyen olarak gruplandırır.'),
  ('FB.5.7.1.2', 'Fen Bilimleri', 5, 7, 'Sürdürülebilir Yaşam ve Geri Dönüşüm', 'Geri dönüşümün kaynak kullanımındaki önemine yönelik bilimsel çıkarımda bulunabilme', 'Geri dönüşümün önemi hakkında veri toplar ve değerlendirir.'),
  ('FB.5.7.1.3', 'Fen Bilimleri', 5, 7, 'Sürdürülebilir Yaşam ve Geri Dönüşüm', 'Atık yönetiminin uygulanabilirliğine ilişkin deneyimlerini yansıtabilme', 'Yakın çevresindeki atık yönetimi deneyimlerini gözden geçirir ve değerlendirir.'),
  ('FB.6.1.1.1', 'Fen Bilimleri', 6, 1, 'Güneş Sistemi ve Tutulmalar', 'Güneş sistemindeki gezegenleri niteliklerine göre sınıflandırabilme', 'Güneş sistemindeki gezegenlerin niteliklerini belirler, niteliklerine göre ayrıştırır ve gruplandırır.'),
  ('FB.6.1.1.2', 'Fen Bilimleri', 6, 1, 'Güneş Sistemi ve Tutulmalar', 'Güneş sistemi ile ilgili bilimsel model oluşturabilme', 'Güneş sistemi ile ilgili model önerir ve geliştirir.'),
  ('FB.6.1.2.1', 'Fen Bilimleri', 6, 1, 'Güneş Sistemi ve Tutulmalar', 'Güneş ve Ay tutulması ile ilgili bilimsel çıkarım yapabilme', 'Güneş ve Ay tutulmasının niteliklerini tanımlar, verilerini kaydeder ve değerlendirir.'),
  ('FB.6.1.2.2', 'Fen Bilimleri', 6, 1, 'Güneş Sistemi ve Tutulmalar', 'Güneş ve Ay tutulması ile ilgili bilimsel model oluşturabilme', 'Güneş ve Ay tutulması ile ilgili model önerir ve geliştirir.'),
  ('FB.6.2.1.1', 'Fen Bilimleri', 6, 2, 'Kuvvetin Etkisinde Hareket', 'Bileşke kuvveti yapılandırabilme', 'Bir cisme etki eden aynı doğrultudaki kuvvetler arasındaki ilişkileri inceleyerek bileşke kuvveti açıklar.'),
  ('FB.6.2.1.2', 'Fen Bilimleri', 6, 2, 'Kuvvetin Etkisinde Hareket', 'Dengelenmiş ve dengelenmemiş kuvvetlerin etkisine yönelik deney yapabilme', 'Dengelenmiş ve dengelenmemiş kuvvetlerin bir cismin hareketine etkisini gösteren deney düzeneği tasarlar ve analiz eder.'),
  ('FB.6.2.2.1', 'Fen Bilimleri', 6, 2, 'Kuvvetin Etkisinde Hareket', 'Sürat ve hız kavramlarını karşılaştırabilme', 'Sürat ve hız kavramlarına ilişkin özellikleri, benzerlikleri ve farklılıkları belirler.'),
  ('FB.6.3.1.1', 'Fen Bilimleri', 6, 3, 'Canlılarda Sistemler', 'Eşeyli ve eşeysiz üremeyi karşılaştırabilme', 'Eşeyli ve eşeysiz üreme arasındaki benzerlikleri ve farklılıkları belirler.'),
  ('FB.6.3.1.2', 'Fen Bilimleri', 6, 3, 'Canlılarda Sistemler', 'Bitkilerde üreme, büyüme ve gelişme hakkında bilimsel çıkarım yapabilme', 'Bitkilerde üreme, büyüme ve gelişme ile ilgili verileri toplar, kaydeder ve değerlendirir.'),
  ('FB.6.3.1.3', 'Fen Bilimleri', 6, 3, 'Canlılarda Sistemler', 'Tohumun çimlenmesine etki eden faktörlere ilişkin hipotez oluşturabilme', 'Tohumun çimlenmesini etkileyen faktörlere yönelik hipotez kurar ve test eder.'),
  ('FB.6.3.1.4', 'Fen Bilimleri', 6, 3, 'Canlılarda Sistemler', 'Hayvanlarda üreme, büyüme ve gelişme hakkında bilimsel çıkarım yapabilme', 'Hayvanlarda üreme, büyüme ve gelişme süreçleri hakkında veri toplayarak çıkarım yapar.'),
  ('FB.6.3.1.5', 'Fen Bilimleri', 6, 3, 'Canlılarda Sistemler', 'İnsanda üremeyi sağlayan yapı ve organlar arasındaki ilişkileri çözümleyebilme', 'İnsanda üremeyi sağlayan yapı ve organların işlevleri arasındaki ilişkileri açıklar.'),
  ('FB.6.3.2.1', 'Fen Bilimleri', 6, 3, 'Canlılarda Sistemler', 'Sinir sisteminin görevlerini model üzerinde gözlemleyebilme', 'Sinir sisteminin yapısı ve görevlerini model üzerinde gözlemler ve açıklar.'),
